module counter12bit_even (
    input clk,
    input rst,
    output [11:0] q
);

    reg [11:0] counter_value;

    always @(posedge clk or posedge rst) begin
        if (rst)
            counter_value <= 12'b000000000000;
        else
            counter_value <= counter_value + 2;
    end

    assign q = counter_value;

endmodule
